label("$140^{\circ}$",(0,0),W);
label("$120^{\circ}$",(0,0.3),E);
draw(C--(0,0)--B);
draw(A--(0,0));
label("$A$",A,SW);
label("$B$",B,NE);
label("$C$",C,SE);
[/asy]

